{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.StartEvent_C];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.StartEvent_C);
        inst.messages[MessageKey.TaskC].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.TaskC];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.TaskC, fireflyTranId);
        inst.gateways[GatewayKey.ReviewC].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.ReportC];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.ReportC, fireflyTranId);
        inst.events[EventKey.EndEvent_C].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Gateway storage g = inst.gateways[GatewayKey.ReviewC];
        require(g.exists, "gateway not set");
        require(g.state == ElementState.ENABLED, "gateway state not allowed");

        g.state = ElementState.COMPLETED;
        emit GatewayDone(instanceId, GatewayKey.ReviewC);
        if (inst.stateMemory.ReadyC == true) {
            inst.messages[MessageKey.ReportC].state = ElementState.ENABLED;
        }
        else {
            inst.events[EventKey.EndEvent_C].state = ElementState.ENABLED;
        }

    }

{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.EndEvent_C];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.EndEvent_C);

    }
